(async () => {
const lang = localStorage.getItem("lang");
const cache = await caches.open("cache");

if (lang == null) {
	window.location.href = "lang.html";
}

if (lang != "en_us") {
    const translation = (await cache.match("./lang/" + lang + ".json")).json() || await fetch("./lang." + lang + ".json").then(res => res.json());
} else {
    const translation = {};
}

if (await cache.match("./lang/" + lang + ".json") == null) {
	cache.add("./lang/" + lang + ".json");
}

const elements = document.querySelectorAll("*");
elements.forEach(el => {
	const original = el.innerText;
	if (translation[original]) {
		console.info("Translating:\t", original, "\t->\t", translation[original]);
		el.innerText = translation[original];
	} else {console.warn("No translation found for:", original);}
});
})();